import {
  forwardRef,
  type ReactNode,
  useEffect,
  useRef,
  useState,
  type MouseEvent as ReactMouseEvent,
  Children,
} from 'react';

import {
  BasicChartTooltip,
  type BasicChartTooltipProps,
} from './BasicChartTooltip/BasicChartTooltip.js';
import { InteractiveChartTooltipVirtualizedSeries } from './InteractiveChartTooltipVirtualizedSeries.js';
import { useMergeRefs } from '../../../../../../core/hooks/useMergeRefs.js';
import { isSlot } from '../../../../../../core/utils/is-slot.js';
import type { Point } from '../../../../types/point.js';
import type { TooltipItem } from '../../../../types/tooltip.js';
import { isTouchableDevice } from '../../../../utils/is-touchable-device.js';
import { useChartTooltip } from '../../shared/hooks/useChartTooltip.js';
import { InteractiveTooltipContext } from '../context/InteractiveTooltipContext.js';
import { Actions } from '../slots/Actions.js';
import { Body } from '../slots/Body.js';
import { Header } from '../slots/Header.js';
import type { VirtualEstimatedSize } from '../types/virtual-estimated-size.js';

export interface InteractiveChartTooltipProps {
  pinned?: boolean;
  itemSize?: VirtualEstimatedSize;
  position: Point;
  /**
   * If true, the tooltip position will update even when pinned.
   * For scroll-responsive tooltips.
   * @defaultValue false
   */
  updatePositionWhenPinned?: boolean;
  onMouseLeave?: (event?: ReactMouseEvent) => void;
  onScrollContent?: (event: Event) => void;
}

/**
 * Iterate the children to load the slots
 * @param children -
 */
function iterateSlots(children?: ReactNode): {
  Header?: ReactNode;
  Body?: (() => ReactNode)[];
  Actions?: ReactNode;
} {
  const slots: {
    Header?: ReactNode;
    Body?: (() => ReactNode)[];
    Actions?: ReactNode;
  } = { Header: undefined, Body: undefined, Actions: undefined };

  Children.forEach(children, (child) => {
    if (isSlot(child, Header)) {
      slots.Header = child.props.children;
    } else if (isSlot(child, Body)) {
      slots.Body = child.props.children;
    } else if (isSlot(child, Actions)) {
      slots.Actions = child.props.children;
    }
  });

  return slots;
}

/**
 * Tooltip specific to the TimeseriesChart and Categorical bar chart.
 */
const _InteractiveChartTooltip = /* @__PURE__ */ forwardRef<
  HTMLDivElement,
  BasicChartTooltipProps & InteractiveChartTooltipProps
>((props, forwardedRef) => {
  const {
    pinned = false,
    chartRef,
    position,
    itemSize,
    updatePositionWhenPinned = false,
    children,
    onMouseLeave,
    onScrollContent,
  } = props;
  const chartTooltipRef = useRef<HTMLDivElement>(null);
  const mergedRefs = useMergeRefs([forwardedRef, chartTooltipRef]);

  const [selectedItem, selectItem] = useState<TooltipItem | undefined>(
    undefined,
  );
  const [hasScrollbar, setHasScrollbar] = useState<boolean>(false);
  const onItemSelected = (e: ReactMouseEvent, item?: TooltipItem) => {
    e.stopPropagation(); // prevent unpinning
    selectItem(item);
  };

  const { placement, updateTooltipPosition } = useChartTooltip(
    chartTooltipRef.current,
  );

  useEffect(() => {
    if (!pinned || isTouchableDevice() || updatePositionWhenPinned) {
      updateTooltipPosition(position);
    }
  }, [
    pinned,
    position.x,
    position.y,
    updatePositionWhenPinned,
    updateTooltipPosition,
  ]);

  useEffect(() => {
    return () => {
      onMouseLeave && onMouseLeave();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // TODO: find out why it breaks when using exhaustive deps

  const { Header, Body } = iterateSlots(children);

  return (
    <InteractiveTooltipContext.Provider
      value={{
        selectedItem,
        selectItem: onItemSelected,
        hasScrollbar,
        setHasScrollbar,
      }}
    >
      <BasicChartTooltip
        ref={mergedRefs}
        placement={placement}
        chartRef={chartRef}
        onMouseLeave={onMouseLeave}
        pinned={pinned}
      >
        <InteractiveChartTooltipVirtualizedSeries
          pinned={pinned}
          itemSize={itemSize}
          header={Header}
          body={Body}
          pointerEvents={pinned}
          onScrollContent={onScrollContent}
        />
      </BasicChartTooltip>
    </InteractiveTooltipContext.Provider>
  );
});

(
  _InteractiveChartTooltip as typeof _InteractiveChartTooltip & {
    displayName: string;
  }
).displayName = 'InteractiveChartTooltip';

/** Slot component for interactive chart tooltip */
export const InteractiveChartTooltip = Object.assign(_InteractiveChartTooltip, {
  Header,
  Body,
  Actions,
});
